mapper.select:
SELECT o.id, o.stocktake_no, o.warehouse_id, w.warehouse_name,
       o.location_id, l.location_name,
       (SELECT GROUP_CONCAT(w2.warehouse_name SEPARATOR ',') FROM wms_warehouse w2
        WHERE JSON_CONTAINS(IFNULL(o.warehouse_ids, JSON_ARRAY(o.warehouse_id)), CAST(w2.id AS CHAR)) AND w2.deleted = 0) AS warehouse_names,
       (SELECT GROUP_CONCAT(l2.location_name SEPARATOR ',') FROM wms_location l2
        WHERE JSON_CONTAINS(IFNULL(o.location_ids, JSON_ARRAY(o.location_id)), CAST(l2.id AS CHAR))) AS location_names,
       o.stocktake_type, o.stocktake_date,
       o.start_at, o.end_at, o.checker_id, o.checker_name,
       o.item_count, o.diff_qty_total, o.profit_amount_total, o.loss_amount_total,
       o.diff_rate, o.status, o.version_no, o.org_id, o.tenant_id,
       o.approved_at, o.created_at, o.updated_at
FROM wms_stocktake_order o
LEFT JOIN wms_warehouse w ON w.id = o.warehouse_id AND w.deleted = 0
LEFT JOIN wms_location l ON l.id = o.location_id
WHERE o.deleted = 0

    AND o.stocktake_no LIKE CONCAT('%', #{q.stocktakeNo}, '%')


    AND o.stocktake_date >= #{q.startDate}


    AND o.stocktake_date <= #{q.endDate}


    AND o.warehouse_id = #{q.warehouseId}


    AND o.location_id = #{q.locationId}


    AND o.status = #{q.status}


    AND o.checker_id = #{q.checkerId}


    AND o.checker_name LIKE CONCAT('%', #{q.checkerName}, '%')


    AND o.org_id = #{q.orgId}


    AND o.org_id IN

        #{oid}



    AND 1 = 0


    AND o.tenant_id = #{q.tenantId}

ORDER BY o.created_at DESC

SELECT o.id, o.stocktake_no, o.warehouse_id, w.warehouse_name, o.location_id, l.location_name, (SELECT GROUP_CONCAT(w2.warehouse_name SEPARATOR ',') FROM wms_warehouse w2 WHERE JSON_CONTAINS(IFNULL(o.warehouse_ids, JSON_ARRAY(o.warehouse_id)), CAST(w2.id AS CHAR)) AND w2.deleted = 0) AS warehouse_names, (SELECT GROUP_CONCAT(l2.location_name SEPARATOR ',') FROM wms_location l2 WHERE JSON_CONTAINS(IFNULL(o.location_ids, JSON_ARRAY(o.location_id)), CAST(l2.id AS CHAR))) AS location_names, o.stocktake_type, o.stocktake_date, o.start_at, o.end_at, o.checker_id, o.checker_name, o.item_count, o.diff_qty_total, o.profit_amount_total, o.loss_amount_total, o.diff_rate, o.surplus_qty, o.deficit_qty, o.surplus_amount, o.deficit_amount, o.remark, o.attachments, o.status, o.approved_by, au.real_name AS approver_name, o.approved_at, o.approve_remark, o.reject_remark, o.void_reason, o.version_no, o.org_id, o.tenant_id, o.created_by, cu.real_name AS creator_name, o.updated_by, uu.real_name AS updater_name, o.created_at, o.updated_at FROM wms_stocktake_order o LEFT JOIN wms_warehouse w ON w.id = o.warehouse_id AND w.deleted = 0 LEFT JOIN wms_location l ON l.id = o.location_id LEFT JOIN auth_user au ON au.id = o.approved_by LEFT JOIN auth_user cu ON cu.id = o.created_by LEFT JOIN auth_user uu ON uu.id = o.updated_by WHERE o.id = #{id} AND o.deleted = 0
AND o.org_id = #{orgId}
AND o.tenant_id = #{tenantId}

SELECT v.id, v.stocktake_id, v.version_no, v.status,
       v.item_count, v.diff_qty_total, v.profit_amount_total, v.loss_amount_total,
       v.submitted_by, u.real_name AS submitter_name, v.submitted_at, v.created_at
FROM wms_stocktake_order_version v
LEFT JOIN auth_user u ON u.id = v.submitted_by
WHERE v.stocktake_id = #{stocktakeId}

    AND v.org_id = #{orgId}


    AND v.tenant_id = #{tenantId}

ORDER BY v.version_no DESC, v.created_at DESC

SELECT v.id, v.stocktake_id, v.version_no, v.stocktake_no, v.warehouse_id, w.warehouse_name, v.location_id, l.location_name, v.stocktake_type, v.stocktake_date, v.start_at, v.end_at, v.checker_id, v.checker_name, v.item_count, v.diff_qty_total, v.profit_amount_total, v.loss_amount_total, v.diff_rate, v.surplus_qty, v.deficit_qty, v.surplus_amount, v.deficit_amount, v.remark, v.attachments, v.status, v.approved_by, au.real_name AS approver_name, v.approved_at, v.approve_remark, v.reject_remark, v.void_reason, v.org_id, v.tenant_id, v.submitted_by, su.real_name AS submitter_name, v.submitted_at, v.created_by, cu.real_name AS creator_name, v.created_at, v.updated_at FROM wms_stocktake_order_version v LEFT JOIN wms_warehouse w ON w.id = v.warehouse_id AND w.deleted = 0 LEFT JOIN wms_location l ON l.id = v.location_id LEFT JOIN auth_user au ON au.id = v.approved_by LEFT JOIN auth_user su ON su.id = v.submitted_by LEFT JOIN auth_user cu ON cu.id = v.created_by WHERE v.stocktake_id = #{stocktakeId} AND v.version_no = #{versionNo}
AND v.org_id = #{orgId}
AND v.tenant_id = #{tenantId}

SELECT COUNT(*)
FROM wms_stocktake_order o
WHERE o.deleted = 0
  AND o.status IN ('draft', 'pending')
  AND (
      o.warehouse_id = #{warehouseId}
      OR JSON_CONTAINS(IFNULL(o.warehouse_ids, JSON_ARRAY(o.warehouse_id)), CAST(#{warehouseId} AS CHAR))
  )

    AND o.id <> #{excludeId}


    AND o.org_id = #{orgId}


    AND o.tenant_id = #{tenantId}



        AND (
            o.location_id IS NULL
            OR o.location_id IS NOT NULL
        )


        AND (
            o.location_id IS NULL
            OR o.location_id = #{locationId}
            OR JSON_CONTAINS(IFNULL(o.location_ids, '[]'), CAST(#{locationId} AS CHAR))
        )

SELECT
    COALESCE(SUM(CASE
        WHEN o.stocktake_date >= #{monthStart}
         AND o.stocktake_date < #{nextMonthStart}
         AND o.status IN ('pending', 'rejected', 'completed')
        THEN 1 ELSE 0 END), 0) AS this_month_count,
    COALESCE(SUM(CASE
        WHEN o.status = 'pending'
        THEN 1 ELSE 0 END), 0) AS pending_count,
    COALESCE(SUM(CASE
        WHEN o.stocktake_date >= #{monthStart}
         AND o.stocktake_date < #{nextMonthStart}
         AND o.status = 'completed'
        THEN o.profit_amount_total ELSE 0 END), 0) AS profit_amount_total,
    COALESCE(SUM(CASE
        WHEN o.stocktake_date >= #{monthStart}
         AND o.stocktake_date < #{nextMonthStart}
         AND o.status = 'completed'
        THEN o.loss_amount_total ELSE 0 END), 0) AS loss_amount_total
FROM wms_stocktake_order o
WHERE o.deleted = 0

    AND o.org_id = #{q.orgId}


    AND o.org_id IN

        #{oid}



    AND 1 = 0


    AND o.tenant_id = #{q.tenantId}

SELECT EXISTS (
    SELECT 1
    FROM wms_stocktake_order
    WHERE deleted = 0
      AND warehouse_id = #{warehouseId}
      AND status IN
      #{status}
)

SELECT EXISTS (
    SELECT 1
    FROM wms_stocktake_order
    WHERE warehouse_id = #{warehouseId}
)

SELECT EXISTS (
    SELECT 1
    FROM wms_stocktake_order
    WHERE deleted = 0
      AND location_id = #{locationId}
      AND status IN
      #{status}
)

SELECT EXISTS (
    SELECT 1
    FROM wms_stocktake_order
    WHERE location_id = #{locationId}
)
